"""
NTRU 密码系统攻击工具

来源: NTRU例题.md

NTRU 是基于格的后量子密码算法，本节包含对 NTRU 的格攻击。
"""

from typing import List, Any
from langchain.tools import tool


@tool
def ntru_basic_attack(h: int, c: int, q: int) -> str:
    """
    NTRU 基础格攻击
    
    NTRU 公钥: h = f^(-1) * g mod q
    密文: c = r * h + m mod q
    
    通过构造格找到短向量 (f, g) 来恢复私钥。
    
    格的构造:
    L = [[1, h],
         [0, q]]
    
    Args:
        h: NTRU 公钥
        c: 密文
        q: 模数
    
    Returns:
        恢复的明文 m
    
    Example:
        >>> ntru_basic_attack(
        ...     ,
        ...     ,
        ...     
        ... )
    """
    try:
        from sageall import Matrix, ZZ
        
        # 构造 NTRU 格
        M = Matrix(ZZ, [[1, h], [0, q]])
        
        # LLL 规约
        L = M.LLL()
        
        # 最短向量应该是 (f, g) 或 (f*q, g)
        shortest = L[0]
        
        f = shortest[0]
        g = shortest[1]
        
        if f < 0:
            f = -f
            g = -g
        
        # 验证: f * h ≡ g (mod q)
        if (f * h) % q == g % q:
            # 恢复明文
            # c = r * h + m mod q
            # m = c * f mod q, 然后 mod f 得到 m
            a = (c * f) % q
            m = (a * pow(f, -1, g)) % g
            
            return f"🎯 NTRU 攻击成功!\n私钥 f = {f}\ng = {g}\n明文 m = {m}"
        else:
            # 尝试其他向量
            for i in range(1, min(5, L.nrows())):
                v = L[i]
                f, g = v[0], v[1]
                if f < 0:
                    f, g = -f, -g
                if (f * h) % q == g % q:
                    a = (c * f) % q
                    m = (a * pow(f, -1, g)) % g
                    return f"🎯 NTRU 攻击成功 (向量{i})!\n私钥 f = {f}\n明文 m = {m}"
            
            return f"⚠️ 未找到有效私钥，最短向量: {shortest}"
            
    except ImportError:
        return "需要 SageMath 环境"
    except Exception as e:
        return f"攻击失败: {e}"


@tool
def ntru_check_parameters(q: int, h: int) -> str:
    """
    检查 NTRU 参数的安全性
    
    分析 NTRU 公钥参数，判断是否存在已知攻击。
    
    Args:
        q: 模数
        h: 公钥
    
    Returns:
        安全性分析
    """
    try:
        from sageall import log, sqrt
        
        # 计算参数规模
        q_bits = int(log(q, 2))
        
        result = ["NTRU 参数分析:"]
        result.append(f"  q = {q} ({q_bits} bits)")
        result.append(f"  h = {h}")
        
        # 估计 f, g 的大小
        # 通常 f ≈ q^0.5, g ≈ q^0.5
        expected_size = sqrt(q)
        result.append(f"  预期私钥大小: ~{expected_size}")
        
        # Hermite 因子检查
        # ||v|| <= sqrt(n) * det(L)^(1/n)
        n = 2
        det_L = q  # det([[1, h], [0, q]]) = q
        hermite_bound = sqrt(n) * det_L ** (1/n)
        
        result.append(f"  Hermite 界: {hermite_bound}")
        result.append(f"  预期 ||(f,g)||: ~{expected_size * sqrt(2)}")
        
        if expected_size * sqrt(2) < hermite_bound:
            result.append("✅ 参数看起来可攻击")
        else:
            result.append("⚠️ 参数可能过于安全")
        
        return "\n".join(result)
        
    except ImportError:
        return "需要 SageMath 环境"
    except Exception as e:
        return f"分析失败: {e}"


def get_ntru_tools() -> List[Any]:
    """获取所有 NTRU 工具"""
    return [
        ntru_basic_attack,
        ntru_check_parameters,
    ]
